def draw(self, context):
    layout = self.layout
    row = layout.row()

    if not updater.invalidupdater:
        if updater.update_ready:
            col = layout.column()
            col.scale_y = 0.7
            col.label(
                "Update ready! Press OK to install " + str(updater.update_version),
                icon="LOOP_FORWARDS"
            )
            col.label("or click outside window to defer", icon="BLANK1")
        elif not updater.update_ready:
            col = layout.column()
            col.scale_y = 0.7
            col.label("No updates available")
            col.label("Press okay to dismiss dialog")
    else:
        layout.label("Updater module error")
        return

    # case: updater.update_ready = None (implicitly handled by else case)
    if updater.update_ready is None:
        layout.label("Check for update now?")

